 edit_flow -after flow_step:innovus_report_late_timing -append flow_step:write_sdf
- Following is an example of inserting an additional step_2 step after the step_1 step: set file_dir [file dirname [ dict get [ info frame [ info frame ] ] file ] ] 
 source ${file_dir}/scripts/run_flow.tcl 
 create_flow_step -name step_2 { 
